#include<bits/stdc++.h>
using namespace std;

int main()
{
    int n;
    scanf("%d",&n);
    long long ans=0,ans1=0;
    priority_queue<int> q;
    priority_queue<int,vector<int>,greater<int>> q1;
    for(int i=1;i<=n;i++)
    {
        int x;
        scanf("%d",&x);
        q.push(x);
        if(x<q.top())
        {
            ans+=q.top()-x;
            q.pop();
            q.push(x);
        }
        q1.push(x);
        if(x>q1.top())
        {
            ans1-=q1.top()-x;
            q1.pop();
            q1.push(x);
        }
    }
    printf("%lld",min(ans,ans1));
    return 0;
}
